"""IORunner — start/end 노드."""

from __future__ import annotations

from typing import Any


class IORunner:
    async def run(self, node: Any, inputs: dict[str, Any], ctx: Any) -> dict[str, Any]:
        if node.function_id == "startnode":
            # input_data를 output 포트에 매핑
            input_data = ctx.input_data if hasattr(ctx, "input_data") else {}
            if isinstance(input_data, dict):
                return input_data
            return {"output": input_data}

        if node.function_id == "endnode":
            # 입력을 수집. Generator면 소비.
            result_parts = []
            for key, value in inputs.items():
                if hasattr(value, "__next__"):
                    # Generator 소비 + 스트리밍
                    chunks = []
                    for chunk in value:
                        chunks.append(str(chunk))
                        ctx.emit({"type": "stream_chunk", "data": {"node_id": node.id, "chunk": chunk}})
                    result_parts.append("".join(chunks))
                elif isinstance(value, str):
                    result_parts.append(value)
                else:
                    result_parts.append(str(value) if value is not None else "")

            return {"result": "\n".join(result_parts) if result_parts else ""}

        return inputs
